// Parse the user's reply to determine which habits were completed
const msg = $node['Telegram Trigger'].json.message;
const reply = (msg.text || '').toLowerCase();

// Smart matching for each habit
const habits = {
  sleep_8h: /sleep|slept|8\s*h|well.rested|good\s*night/i.test(reply),
  eat_healthy: /eat|ate|healthy|clean|on\s*plan|nutrition/i.test(reply),
  workout_done: /workout|gym|train|weights|cardio|exercise|lift|run|yoga/i.test(reply),
  steps_10k: /step|walk|10k|10,?000/i.test(reply),
  read_30min: /read|book|learn|study|article|podcast/i.test(reply),
  supplements: /supplement|pill|vitamin|magnesium|omega|creatine/i.test(reply),
  positivity: /positiv|grateful|thankful|gratefulness|mindful|meditat/i.test(reply),
  calendar_reflection: /calendar|reflect|plan|journal|review/i.test(reply)
};

// Retrieve food context stored by the evening cron
const stateContext = $node['Fetch Conversation State'].json.context || {};
const totalCal = stateContext.totalCal || 0;
const totalProtein = stateContext.totalProtein || 0;
const totalCarbs = stateContext.totalCarbs || 0;
const totalFat = stateContext.totalFat || 0;
const mealCount = stateContext.mealCount || 0;
const isTrainingDay = stateContext.isTrainingDay || false;
const goal = stateContext.goal || 1900;

// If food was logged today, auto-check eat_healthy based on calorie adherence
if (totalCal > 0 && totalCal <= goal + 100 && totalProtein >= 140) {
  habits.eat_healthy = true;
}

// Count completed habits
const completed = Object.values(habits).filter(Boolean).length;
const total = Object.keys(habits).length;
const percentage = Math.round((completed / total) * 100);

return [{ json: { habits, completed, total, percentage, rawReply: reply, totalCal, totalProtein, totalCarbs, totalFat, mealCount, isTrainingDay, goal } }];

// Check if a Notion page was found for today, or create one
const results = $json.results || [];
const habits = $node['Parse Check-in Reply'].json.habits;
const parsedData = $node['Parse Check-in Reply'].json;

if (results.length > 0) {
  // Page exists - use it
  return [{ json: { notionPageId: results[0].id, action: 'update', habits, parsedData } }];
} else {
  // No page for today - need to create one
  return [{ json: { notionPageId: null, action: 'create', habits, parsedData } }];
}

