// Handle bot commands
const text = ($node['Telegram Trigger'].json.message.text || '').trim();
const cmd = text.split(' ')[0].toLowerCase();

let reply = '';

switch (cmd) {
  case '/help':
    reply = `Available commands:
/help - Show this message
/totals - Today's food totals
/training - Toggle training day
/recap - Quick weekly summary

Or just send me:
- Text describing what you ate
- A photo of your food
- A voice note about your meal`;
    break;
  case '/totals':
    reply = 'FETCHING_TOTALS';
    break;
  case '/training':
    reply = 'TOGGLE_TRAINING';
    break;
  case '/recap':
    reply = 'WEEKLY_RECAP';
    break;
  default:
    reply = `Unknown command: ${cmd}\nTry /help for available commands.`;
}

return [{ json: { reply, cmd } }];

// Convert downloaded binary image to base64 for Claude vision API
const binaryData = $input.item.binary;
if (!binaryData || !binaryData.data) {
  throw new Error('No binary data found from photo download');
}

const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64 = buffer.toString('base64');

// Determine media type from file extension
const fileName = binaryData.data.fileName || 'photo.jpg';
let mediaType = 'image/jpeg';
if (fileName.endsWith('.png')) mediaType = 'image/png';
else if (fileName.endsWith('.webp')) mediaType = 'image/webp';
else if (fileName.endsWith('.gif')) mediaType = 'image/gif';

// Build photo URL for storage
const filePath = $node['Get Photo File'].json.result.file_path;

return [{ json: { base64, mediaType, photoUrl: `telegram://file/${filePath}`, caption: $node['Telegram Trigger'].json.message.caption || 'See attached photo' } }];

// Build context for photo analysis
const meals = $input.all().map(i => i.json);

let runningTotal = { calories: 0, protein: 0, carbs: 0, fat: 0, fiber: 0 };
let mealList = [];

for (const meal of meals) {
  runningTotal.calories += meal.calories || 0;
  runningTotal.protein += parseFloat(meal.protein_g) || 0;
  runningTotal.carbs += parseFloat(meal.carbs_g) || 0;
  runningTotal.fat += parseFloat(meal.fat_g) || 0;
  runningTotal.fiber += parseFloat(meal.fiber_g) || 0;
  mealList.push(`- ${meal.meal_name}: ${meal.calories} kcal, P:${meal.protein_g}g C:${meal.carbs_g}g F:${meal.fat_g}g`);
}

const today = new Date();
const dayOfWeek = today.getDay();
const isTrainingDay = [1, 3, 5].includes(dayOfWeek);
const calorieGoal = isTrainingDay ? 2100 : 1900;

const context = `Today: ${today.toISOString().split('T')[0]} | ${isTrainingDay ? 'Training' : 'Rest'} day (${calorieGoal} kcal goal)\nMeals so far: ${meals.length}\n${mealList.join('\n')}\nRunning: ${runningTotal.calories}/${calorieGoal} kcal | P: ${runningTotal.protein.toFixed(1)}/170g`;

return [{ json: { context, isTrainingDay, calorieGoal, runningTotal } }];

// Parse Claude's response and extract macro values
const response = $json.content[0].text;

const calorieMatch = response.match(/Calories:\s*(\d+)/i);
const proteinMatch = response.match(/P(?:rotein)?:\s*([\d.]+)/i);
const carbsMatch = response.match(/C(?:arbs)?:\s*([\d.]+)/i);
const fatMatch = response.match(/F(?:at)?:\s*([\d.]+)/i);
const fiberMatch = response.match(/Fiber:\s*([\d.]+)/i);
const sodiumMatch = response.match(/Sodium:\s*([\d.]+)/i);

const lines = response.split('\n').filter(l => l.trim());
const mealName = lines[0].replace(/^[^a-zA-Z]*/, '').trim();

let foodQuality = 'decent';
if (response.match(/ultra.processed|junk|lazy|terrible/i)) foodQuality = 'junk';
else if (response.match(/processed|mediocre|not great/i)) foodQuality = 'processed';
else if (response.match(/clean|perfect|excellent|great fuel/i)) foodQuality = 'clean';

const commentLines = response.split('\n').filter(l => l.startsWith('"') || l.startsWith('\u201c') || l.includes('\u2014') || l.includes('-'));
const aiComment = commentLines.length > 0 ? commentLines[commentLines.length - 1].replace(/^["\u201c]|["\u201d]$/g, '').trim() : '';

// Infer meal type from current hour
const hour = new Date().getHours();
let mealType = 'snack';
if (hour < 11) mealType = 'breakfast';
else if (hour < 14) mealType = 'lunch';
else if (hour >= 17) mealType = 'dinner';

return [{
  json: {
    meal_name: mealName || 'Meal',
    meal_type: mealType,
    calories: parseInt(calorieMatch?.[1]) || 0,
    protein_g: parseFloat(proteinMatch?.[1]) || 0,
    carbs_g: parseFloat(carbsMatch?.[1]) || 0,
    fat_g: parseFloat(fatMatch?.[1]) || 0,
    fiber_g: fiberMatch ? parseFloat(fiberMatch[1]) : null,
    sodium_mg: sodiumMatch ? parseFloat(sodiumMatch[1]) : null,
    food_quality: foodQuality,
    ai_comment: aiComment,
    claude_response: response
  }
}];

// Use the transcribed text as the meal description
const transcription = $json.text || '';
return [{ json: { text: transcription, inputType: 'voice' } }];

// Build context for Claude from today's meals
const meals = $input.all().map(i => i.json);

let runningTotal = { calories: 0, protein: 0, carbs: 0, fat: 0, fiber: 0 };
let mealList = [];

for (const meal of meals) {
  runningTotal.calories += meal.calories || 0;
  runningTotal.protein += parseFloat(meal.protein_g) || 0;
  runningTotal.carbs += parseFloat(meal.carbs_g) || 0;
  runningTotal.fat += parseFloat(meal.fat_g) || 0;
  runningTotal.fiber += parseFloat(meal.fiber_g) || 0;
  mealList.push(`- ${meal.meal_name}: ${meal.calories} kcal, P:${meal.protein_g}g C:${meal.carbs_g}g F:${meal.fat_g}g`);
}

const today = new Date();
const dayOfWeek = today.getDay();
const isTrainingDay = [1, 3, 5].includes(dayOfWeek);
const calorieGoal = isTrainingDay ? 2100 : 1900;

const context = `\n## Today's Date: ${today.toISOString().split('T')[0]}\n## Training Day: ${isTrainingDay ? 'YES (2100 kcal goal)' : 'NO (1900 kcal goal)'}\n## Meals so far today (${meals.length} meals):\n${mealList.length > 0 ? mealList.join('\n') : 'No meals logged yet'}\n\n## Running Total:\nCalories: ${runningTotal.calories} / ${calorieGoal} kcal\nProtein: ${runningTotal.protein.toFixed(1)} / 170 g\nCarbs: ${runningTotal.carbs.toFixed(1)} g\nFat: ${runningTotal.fat.toFixed(1)} g\nFiber: ${runningTotal.fiber.toFixed(1)} g\nRemaining: ${calorieGoal - runningTotal.calories} kcal | ${(170 - runningTotal.protein).toFixed(1)}g protein\n`;

return [{ json: { context, isTrainingDay, calorieGoal, runningTotal } }];

// Parse Claude's response and extract macro values
const response = $json.content[0].text;

const calorieMatch = response.match(/Calories:\s*(\d+)/i);
const proteinMatch = response.match(/P(?:rotein)?:\s*([\d.]+)/i);
const carbsMatch = response.match(/C(?:arbs)?:\s*([\d.]+)/i);
const fatMatch = response.match(/F(?:at)?:\s*([\d.]+)/i);
const fiberMatch = response.match(/Fiber:\s*([\d.]+)/i);
const sodiumMatch = response.match(/Sodium:\s*([\d.]+)/i);

const lines = response.split('\n').filter(l => l.trim());
const mealName = lines[0].replace(/^[^a-zA-Z]*/, '').trim();

let foodQuality = 'decent';
if (response.match(/ultra.processed|junk|lazy|terrible/i)) foodQuality = 'junk';
else if (response.match(/processed|mediocre|not great/i)) foodQuality = 'processed';
else if (response.match(/clean|perfect|excellent|great fuel/i)) foodQuality = 'clean';

const commentLines = response.split('\n').filter(l => l.startsWith('"') || l.startsWith('\u201c') || l.includes('\u2014') || l.includes('-'));
const aiComment = commentLines.length > 0 ? commentLines[commentLines.length - 1].replace(/^["\u201c]|["\u201d]$/g, '').trim() : '';

// Infer meal type from current hour
const hour = new Date().getHours();
let mealType = 'snack';
if (hour < 11) mealType = 'breakfast';
else if (hour < 14) mealType = 'lunch';
else if (hour >= 17) mealType = 'dinner';

// Determine input type (voice or text)
const inputType = $node['Voice to Text']?.json?.inputType || 'text';
const description = $node['Telegram Trigger'].json.message.text || $node['Voice to Text']?.json?.text || '';

return [{
  json: {
    meal_name: mealName || 'Meal',
    meal_type: mealType,
    description: description,
    calories: parseInt(calorieMatch?.[1]) || 0,
    protein_g: parseFloat(proteinMatch?.[1]) || 0,
    carbs_g: parseFloat(carbsMatch?.[1]) || 0,
    fat_g: parseFloat(fatMatch?.[1]) || 0,
    fiber_g: fiberMatch ? parseFloat(fiberMatch[1]) : null,
    sodium_mg: sodiumMatch ? parseFloat(sodiumMatch[1]) : null,
    food_quality: foodQuality,
    ai_comment: aiComment,
    input_type: inputType,
    claude_response: response
  }
}];
